const token = $input.first().json.headers['x-admin-token'];
if (!token) return [{json: {ok: 'false', error: 'No autorizado'}}];
try {
  const decoded = Buffer.from(token, 'base64').toString('utf8');
  const parts = decoded.split('|');
  if (parts.length !== 3 || parts[2] !== 'CrackTesos2026_Admin_Token') return [{json: {ok: 'false', error: 'Token inválido'}}];
  const age = Date.now() - parseInt(parts[1]);
  if (age > 8 * 3600 * 1000) return [{json: {ok: 'false', error: 'Sesión expirada'}}];
  return [{json: {ok: 'true', email: parts[0]}}];
} catch(e) { return [{json: {ok: 'false', error: 'Token inválido'}}]; }

function parseData(nodeName) {
  const raw = $(nodeName).first().json.data;
  return Array.isArray(raw) ? raw : (raw ? JSON.parse(raw) : []);
}

const detalle = parseData('Query Detalle');
const resumen = parseData('Query Resumen');
const totales = parseData('Query Totales');

return [{json: {
  ok: true,
  generated_at: new Date().toLocaleString('es-CO', {timeZone: 'America/Bogota'}),
  detalle,
  resumen,
  totales
}}];
